"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter, useSearchParams } from "next/navigation";
import Link from "next/link";
import { api, type MenuItem, type Ingredient, type Category, type MenuOptionGroup, type DrinkSizesResponse, type DrinkMode, type DrinkSizesByModePayload, type MenuItemSizePrice, type RecipeLineSize, type MenuSize, normalizeCategoriesResponse, normalizeSubCategories } from "@/lib/api";

const API = process.env.NEXT_PUBLIC_API_URL || "http://localhost:4000";

function parseQty(v: number | string): number {
  if (typeof v === "number") return v;
  const n = parseFloat(String(v));
  return Number.isNaN(n) ? 0 : n;
}

const TOAST_KEY = "items_toast";

const DEFAULT_DRINK_SIZES_BY_MODE: DrinkSizesByModePayload["drinkSizesByMode"] = {
  ICED: { enabledOptionIds: [], defaultOptionId: null },
  HOT: { enabledOptionIds: [], defaultOptionId: null },
  CONCENTRATED: { enabledOptionIds: [], defaultOptionId: null },
};

const DRINK_MODES: DrinkMode[] = ["ICED", "HOT", "CONCENTRATED"];

const MODE_LABELS: Record<DrinkMode, string> = {
  HOT: "Hot",
  ICED: "Iced",
  CONCENTRATED: "Concentrated",
};

type SizeRecipeLine = {
  ingredientId: string;
  baseType: DrinkMode;
  sizeCode: string;
  qtyPerItem: number;
  unitCode: string;
};

export default function EditItemPage() {
  const params = useParams();
  const router = useRouter();
  const searchParams = useSearchParams();
  const id = params.id as string;
  const includeDeleted = searchParams.get("includeDeleted") === "1";
  const [item, setItem] = useState<MenuItem | null>(null);
  const [ingredients, setIngredients] = useState<Ingredient[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [optionGroups, setOptionGroups] = useState<MenuOptionGroup[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);
  const [name, setName] = useState("");
  const [pricePesos, setPricePesos] = useState("");
  const [isActive, setIsActive] = useState(true);
  const [categoryId, setCategoryId] = useState("");
  const [subCategoryId, setSubCategoryId] = useState("");
  const [selectedGroupIds, setSelectedGroupIds] = useState<string[]>([]);
  const [hasSizes, setHasSizes] = useState(false);
  const [drinkSizesByMode, setDrinkSizesByMode] = useState<DrinkSizesByModePayload["drinkSizesByMode"]>(DEFAULT_DRINK_SIZES_BY_MODE);
  const [sizePricesByMode, setSizePricesByMode] = useState<DrinkSizesByModePayload["sizePricesByMode"]>({});
  const [drinkSizes, setDrinkSizes] = useState<DrinkSizesResponse | null>(null);
  const [drinkSizesError, setDrinkSizesError] = useState<string | null>(null);
  const [menuSizes, setMenuSizes] = useState<MenuSize[]>([]);
  const [sizeAvailability, setSizeAvailability] = useState<{
    ICED: string[];
    HOT: string[];
    CONCENTRATED: string[];
  }>({
    ICED: [],
    HOT: [],
    CONCENTRATED: [],
  });
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [recipeLines, setRecipeLines] = useState<{ ingredientId: string; qtyPerItem: number; unitCode: string }[]>([]);
  const [sizeRecipeLines, setSizeRecipeLines] = useState<SizeRecipeLine[]>([]);
  const [newIngredientId, setNewIngredientId] = useState("");
  const [newQty, setNewQty] = useState("");
  const [newUnitCode, setNewUnitCode] = useState("");

  useEffect(() => {
    Promise.all([api.getDrinkSizes(), api.getMenuSizes()])
      .then(([sizesFromOptions, menuSizesResult]) => {
        setDrinkSizes(sizesFromOptions);
        setMenuSizes(menuSizesResult.sizes ?? []);
        if (menuSizesResult.availability) {
          setSizeAvailability({
            ICED: menuSizesResult.availability.ICED ?? [],
            HOT: menuSizesResult.availability.HOT ?? [],
            CONCENTRATED: menuSizesResult.availability.CONCENTRATED ?? [],
          });
        }
      })
      .catch(() => {
        setDrinkSizesError(
          "Missing drink size configuration. Run db:seed in cloud-api and ensure Menu Settings → Sizes is configured."
        );
      });
  }, []);

  useEffect(() => {
    Promise.all([
      api.getItem(id, includeDeleted),
      api.getRecipe(id),
      api.getIngredients(),
      api.getCategories(),
      api.getOptionGroups(),
    ])
      .then(([i, recipe, ings, cats, groups]) => {
        setItem(i);
        setName(i.name);
        setPricePesos((i.priceCents / 100).toFixed(2));
        setIsActive(i.isActive);
        setCategoryId(i.categoryId ?? i.subCategory?.categoryId ?? "");
        setSubCategoryId(i.subCategoryId ?? "");
        const configs = i.drinkSizeConfigs ?? [];
        const defaults = i.drinkModeDefaults ?? [];
        const initialHasSizes = i.hasSizes ?? (configs.length > 0 || defaults.length > 0);
        if (configs.length > 0 || defaults.length > 0) {
          const next = { ...DEFAULT_DRINK_SIZES_BY_MODE };
          for (const mode of DRINK_MODES) {
            next[mode].enabledOptionIds = configs.filter((c) => c.mode === mode && c.isEnabled).map((c) => c.optionId);
            const def = defaults.find((d) => d.mode === mode);
            next[mode].defaultOptionId = def ? def.defaultOptionId : null;
          }
          setDrinkSizesByMode(next);
          setHasSizes(initialHasSizes && DRINK_MODES.some((mode) => next[mode].enabledOptionIds.length > 0));
        } else {
          setDrinkSizesByMode(DEFAULT_DRINK_SIZES_BY_MODE);
          setHasSizes(initialHasSizes);
        }
        // Initialize sizePricesByMode from item.sizePrices (if any)
        const sizePrices = (i.sizePrices ?? []) as MenuItemSizePrice[];
        if (sizePrices.length > 0) {
          const byMode: NonNullable<DrinkSizesByModePayload["sizePricesByMode"]> = {};
          for (const mode of DRINK_MODES) {
            const entries = sizePrices.filter((p) => p.baseType === mode);
            if (entries.length > 0) {
              const map: Record<string, number> = {};
              for (const p of entries) {
                map[p.sizeOptionId] = p.priceCents;
              }
              (byMode as any)[mode] = map;
            }
          }
          setSizePricesByMode(byMode);
        } else {
          setSizePricesByMode({});
        }
        setSelectedGroupIds((i.optionGroupLinks ?? []).map((l) => l.groupId));
        setRecipeLines(
          (recipe.lines ?? []).map((r) => ({
            ingredientId: r.ingredientId,
            qtyPerItem: parseQty(r.qtyPerItem),
            unitCode: r.unitCode,
          }))
        );
        setSizeRecipeLines(
          (recipe.sizeLines ?? []).map((r: RecipeLineSize) => ({
            ingredientId: r.ingredientId,
            baseType: r.baseType,
            sizeCode: r.sizeCode,
            qtyPerItem: parseQty(r.qtyPerItem),
            unitCode: r.unitCode,
          }))
        );
        setIngredients(Array.isArray(ings) ? ings : []);
        setCategories(normalizeCategoriesResponse(cats).categories);
        setOptionGroups(Array.isArray(groups) ? groups : []);
        if (ings.length) setNewUnitCode(ings[0].unitCode);
        setImagePreview(null);
      })
      .catch((e) => setError(e instanceof Error ? e.message : "Failed to load"))
      .finally(() => setLoading(false));
  }, [id, includeDeleted]);

  useEffect(() => {
    if (!imageFile) {
      setImagePreview(null);
      return;
    }
    const url = URL.createObjectURL(imageFile);
    setImagePreview(url);
    return () => URL.revokeObjectURL(url);
  }, [imageFile]);

  async function saveItem(e: React.FormEvent) {
    e.preventDefault();
    setError("");
    const peso = parseFloat(pricePesos);
    if (Number.isNaN(peso) || peso < 0) {
      setError("Price must be a non-negative number.");
      return;
    }
    if (!categoryId || !subCategoryId) {
      setError("Category and subcategory are required.");
      return;
    }
    if (hasSizes) {
      const modesWithEnabledNoDefault = DRINK_MODES.filter(
        (mode) => drinkSizesByMode[mode].enabledOptionIds.length > 0 && !drinkSizesByMode[mode].defaultOptionId
      );
      if (modesWithEnabledNoDefault.length > 0) {
        setError(`Select a default size for: ${modesWithEnabledNoDefault.map((m) => MODE_LABELS[m]).join(", ")}.`);
        return;
      }
      // When item has sizes, require a price for every enabled size
      const missingPrices: string[] = [];
      for (const mode of DRINK_MODES) {
        const { enabledOptionIds } = drinkSizesByMode[mode];
        if (enabledOptionIds.length === 0) continue;
        const modePrices = sizePricesByMode?.[mode] ?? {};
        for (const optId of enabledOptionIds) {
          const raw = modePrices[optId];
          if (raw === undefined || Number.isNaN(raw) || raw < 0) {
            missingPrices.push(`${MODE_LABELS[mode]} - option ${optId}`);
          }
        }
      }
      if (missingPrices.length > 0) {
        setError("Enter a non-negative price for every enabled size.");
        return;
      }
    }

    // Derive base price cents. For size-based items, use the first default size price if available.
    let priceCents = Math.round(peso * 100);
    if (hasSizes) {
      let derived: number | null = null;
      for (const mode of DRINK_MODES) {
        const { defaultOptionId } = drinkSizesByMode[mode];
        if (defaultOptionId) {
          const cents = sizePricesByMode?.[mode]?.[defaultOptionId];
          if (typeof cents === "number" && cents >= 0) {
            derived = cents;
            break;
          }
        }
      }
      if (derived === null) {
        // Fallback: minimum of all configured size prices
        let min: number | null = null;
        for (const mode of DRINK_MODES) {
          const map = sizePricesByMode?.[mode];
          if (!map) continue;
          for (const v of Object.values(map)) {
            if (typeof v !== "number" || v < 0) continue;
            if (min === null || v < min) min = v;
          }
        }
        if (min !== null) derived = min;
      }
      if (derived !== null) {
        priceCents = derived;
      }
    }
    setSaving(true);
    try {
      await api.updateItem(id, {
        name,
        priceCents,
        isActive,
        categoryId: categoryId || null,
        subCategoryId,
        defaultSizeOptionId: item?.defaultSizeOptionId ?? null,
        hasSizes,
      });
      // Always persist drink sizes: when hasSizes is false we send all empty to clear config
      const payload = hasSizes ? drinkSizesByMode : DEFAULT_DRINK_SIZES_BY_MODE;
      const sizePricesPayload: DrinkSizesByModePayload["sizePricesByMode"] | undefined = hasSizes
        ? sizePricesByMode
        : undefined;
      await api.putItemDrinkSizes(id, {
        drinkSizesByMode: payload,
        hasSizes,
        sizePricesByMode: sizePricesPayload,
      });
      if (imageFile) {
        await api.uploadItemImage(id, imageFile);
        setImageFile(null);
      }
      await api.putItemOptionGroups(id, selectedGroupIds);
      setItem(null);
      const [i] = await Promise.all([api.getItem(id)]);
      setItem(i);
    } catch (err) {
      const body = (err as { body?: { message?: string } })?.body;
      setError(body?.message ?? (err instanceof Error ? err.message : "Failed to update. Check category/subcategory."));
    } finally {
      setSaving(false);
    }
  }

  async function saveRecipe() {
    setError("");
    setSaving(true);
    try {
      const baseLinesPayload = recipeLines.map((r) => ({
        ingredientId: r.ingredientId,
        qtyPerItem: r.qtyPerItem,
        unitCode: r.unitCode,
      }));
      const sizeLinesPayload =
        hasSizes && sizeRecipeLines.length > 0
          ? sizeRecipeLines
              .filter((r) => r.qtyPerItem > 0)
              .map((r) => ({
                ingredientId: r.ingredientId,
                baseType: r.baseType,
                sizeCode: r.sizeCode,
                qtyPerItem: r.qtyPerItem,
                unitCode: r.unitCode,
              }))
          : undefined;

      await api.putRecipe(id, baseLinesPayload, sizeLinesPayload);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to save recipe");
    } finally {
      setSaving(false);
    }
  }

  function addRecipeLine() {
    if (!newIngredientId || newQty === "") return;
    const qty = parseFloat(newQty);
    if (Number.isNaN(qty) || qty < 0) return;
    const unit = newUnitCode.trim() || "unit";
    setRecipeLines((prev) => [...prev, { ingredientId: newIngredientId, qtyPerItem: qty, unitCode: unit }]);
    setNewIngredientId("");
    setNewQty("");
  }

  function removeRecipeLine(index: number) {
    setRecipeLines((prev) => prev.filter((_, i) => i !== index));
    setSizeRecipeLines((prev) => {
      const ingredientId = recipeLines[index]?.ingredientId;
      if (!ingredientId) return prev;
      return prev.filter((r) => r.ingredientId !== ingredientId);
    });
  }

  function toggleOptionGroup(groupId: string) {
    setSelectedGroupIds((prev) =>
      prev.includes(groupId) ? prev.filter((g) => g !== groupId) : [...prev, groupId]
    );
  }

  const ingredientName = (ingredientId: string) => ingredients.find((i) => i.id === ingredientId)?.name ?? ingredientId;
  const safeCategories = Array.isArray(categories) ? categories : [];
  const subCategories = categoryId
    ? normalizeSubCategories(safeCategories.find((c) => c.id === categoryId)?.subCategories)
    : [];

  function setModeEnabled(mode: DrinkMode, optionId: string, enabled: boolean) {
    setDrinkSizesByMode((prev) => {
      const next = { ...prev };
      const enabledIds = enabled
        ? [...prev[mode].enabledOptionIds, optionId]
        : prev[mode].enabledOptionIds.filter((id) => id !== optionId);
      let defaultId = prev[mode].defaultOptionId;
      if (!enabled && defaultId === optionId) defaultId = null;
      next[mode] = { enabledOptionIds: enabledIds, defaultOptionId: defaultId };
      return next;
    });
  }

  function setModeDefault(mode: DrinkMode, defaultOptionId: string | null) {
    setDrinkSizesByMode((prev) => ({
      ...prev,
      [mode]: { ...prev[mode], defaultOptionId },
    }));
  }

  async function handleDeleteItem() {
    if (!confirm(`Delete item "${item?.name}"?`)) return;
    setError("");
    setSaving(true);
    try {
      await api.deleteItem(id);
      if (typeof sessionStorage !== "undefined") sessionStorage.setItem(TOAST_KEY, "Item deleted");
      router.replace("/menu");
    } catch (err) {
      const msg = err instanceof Error ? err.message : "Failed to delete";
      setError(msg);
      console.error("[handleDeleteItem] failed:", { itemId: id, error: err });
      setSaving(false);
    }
  }

  async function handleRestoreItem() {
    if (!confirm(`Restore item "${item?.name}"?`)) return;
    setError("");
    setSaving(true);
    try {
      await api.restoreItem(id);
      if (typeof sessionStorage !== "undefined") sessionStorage.setItem(TOAST_KEY, "Item restored");
      router.replace(`/menu`);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to restore");
      setSaving(false);
    }
  }

  if (loading) return <div className="mx-auto max-w-6xl px-4 py-6">Loading…</div>;
  if (error && !item) return <div className="mx-auto max-w-6xl px-4 py-6 text-red-600">{error}</div>;
  if (!item) return null;

  if (item.deletedAt) {
    return (
      <div className="mx-auto max-w-6xl px-4 py-6">
        <div className="mb-4">
          <Link href="/menu?includeDeleted=1" className="text-gray-500 hover:text-gray-700">← Menu</Link>
        </div>
        <div className="rounded border border-amber-200 bg-amber-50 p-6">
          <h1 className="mb-2 text-xl font-semibold text-amber-800">Item deleted</h1>
          <p className="mb-4 text-amber-700">{item.name} has been deleted. Restore it to make it visible again.</p>
          {error && <p className="mb-3 text-sm text-red-600">{error}</p>}
          <div className="flex gap-3">
            <button
              type="button"
              onClick={handleRestoreItem}
              disabled={saving}
              className="rounded bg-green-600 px-4 py-2 text-sm text-white hover:bg-green-700 disabled:opacity-50"
            >
              {saving ? "Restoring…" : "Restore item"}
            </button>
            <Link href="/menu?includeDeleted=1" className="rounded border border-gray-300 px-4 py-2 text-sm text-gray-700 hover:bg-gray-50">
              Back to items
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="mx-auto max-w-6xl px-4 py-6">
      <div className="mb-4 flex items-center justify-between">
        <Link href="/menu" className="text-gray-500 hover:text-gray-700">← Menu</Link>
        <button
          type="button"
          onClick={handleDeleteItem}
          disabled={saving}
          className="rounded border border-red-200 px-3 py-1.5 text-sm text-red-600 hover:bg-red-50 disabled:opacity-50"
        >
          Delete item
        </button>
      </div>
      <h1 className="mb-4 text-2xl font-semibold">Edit Item</h1>

      <form onSubmit={saveItem} className="mb-8 max-w-md space-y-4 rounded border bg-white p-4">
        <div>
          <label className="mb-1 block text-sm font-medium text-gray-700">Image</label>
          <div className="flex items-center gap-3">
            {imagePreview ? (
              <img
                src={imagePreview}
                alt=""
                className="h-20 w-20 rounded object-cover border border-gray-200"
              />
            ) : item.imageUrl ? (
              <img
                src={item.imageUrl.startsWith("http") ? item.imageUrl : `${API}${item.imageUrl}`}
                alt=""
                className="h-20 w-20 rounded object-cover border border-gray-200"
              />
            ) : (
              <div className="flex h-20 w-20 items-center justify-center rounded border border-dashed border-gray-300 bg-gray-50 text-gray-400 text-xs">
                No image
              </div>
            )}
            <div>
              <input
                type="file"
                accept="image/*"
                onChange={(e) => setImageFile(e.target.files?.[0] ?? null)}
                className="text-sm"
              />
              {imageFile && <p className="mt-1 text-xs text-gray-500">{imageFile.name}</p>}
            </div>
          </div>
        </div>
        <div>
          <label className="mb-1 block text-sm font-medium text-gray-700">Name</label>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
            className="w-full rounded border border-gray-300 px-3 py-2 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
          />
        </div>
        {!hasSizes && (
          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">Base Price (₱)</label>
            <input
              type="number"
              min={0}
              step="0.01"
              value={pricePesos}
              onChange={(e) => setPricePesos(e.target.value)}
              required={!hasSizes}
              className="w-full rounded border border-gray-300 px-3 py-2 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
            />
          </div>
        )}
        <div>
          <label className="mb-1 block text-sm font-medium text-gray-700">Category</label>
          <select
            value={categoryId}
            onChange={(e) => {
              setCategoryId(e.target.value);
              setSubCategoryId("");
            }}
            className="w-full rounded border border-gray-300 px-3 py-2 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
          >
            <option value="">—</option>
            {safeCategories.map((c) => (
              <option key={c.id} value={c.id}>{c.name}</option>
            ))}
          </select>
        </div>
        {categoryId && (
          <div>
            <label className="mb-1 block text-sm font-medium text-gray-700">Subcategory <span className="text-red-500">*</span></label>
            <select
              value={subCategoryId}
              onChange={(e) => setSubCategoryId(e.target.value)}
              required
              className="w-full rounded border border-gray-300 px-3 py-2 focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500"
            >
              <option value="">Select subcategory</option>
              {subCategories.map((sc) => (
                <option key={sc.id} value={sc.id}>{sc.name}</option>
              ))}
            </select>
            {subCategories.length === 0 && (
              <p className="mt-1 text-xs text-amber-600">No subcategories. Create one in Categories.</p>
            )}
          </div>
        )}
        <div className="rounded border border-gray-200 bg-gray-50 p-3">
          <label className="mb-2 flex items-center gap-2 text-sm font-medium text-gray-700">
            <input
              type="checkbox"
              checked={hasSizes}
              onChange={(e) => {
                const checked = e.target.checked;
                setHasSizes(checked);
                if (!checked) setDrinkSizesByMode(DEFAULT_DRINK_SIZES_BY_MODE);
              }}
              className="rounded border-gray-300"
            />
            Has Sizes
          </label>
          <p className="mb-2 text-xs text-gray-500">
            When checked, this item can have size options (e.g. 12oz, 16oz) per mode. When unchecked, the item behaves as a normal non-size item.
          </p>
          {drinkSizesError && (
            <div className="rounded border border-amber-300 bg-amber-50 p-3">
              <p className="mb-2 text-sm font-medium text-amber-800">{drinkSizesError}</p>
              <Link
                href="/menu-settings/sizes"
                className="inline-block rounded bg-amber-600 px-3 py-1.5 text-sm text-white hover:bg-amber-700"
              >
                Go to Menu Settings → Sizes
              </Link>
            </div>
          )}
          {hasSizes && drinkSizes && drinkSizes.options.length > 0 && (
            <div className="mt-3 space-y-4">
              <p className="text-xs text-gray-500">
                Enable sizes and set prices per mode. Price is required when a size is enabled.
              </p>
              {DRINK_MODES.map((mode) => {
                const { enabledOptionIds, defaultOptionId } = drinkSizesByMode[mode];
                const enabledForDefault = drinkSizes.options.filter((o) => enabledOptionIds.includes(o.id));
                const hasEnabledNoDefault = enabledOptionIds.length > 0 && !defaultOptionId;
                const modePrices = sizePricesByMode?.[mode] ?? {};

                // Derive which size labels are globally available for this mode from Menu Settings
                const idsForMode = sizeAvailability[mode] ?? [];
                const sizeById = new Map(menuSizes.map((s) => [s.id, s.label]));
                const allowedLabels = new Set(
                  idsForMode
                    .map((id) => sizeById.get(id))
                    .filter((label): label is string => !!label)
                );

                const modeOptions =
                  allowedLabels.size > 0
                    ? drinkSizes.options.filter((o) => allowedLabels.has(o.label))
                    : drinkSizes.options;

                return (
                  <div key={mode} className="rounded border border-gray-200 bg-white p-3">
                    <h4 className="mb-3 text-sm font-semibold text-gray-700">{MODE_LABELS[mode]}</h4>
                    <div className="space-y-2">
                      {modeOptions.map((o) => {
                        const enabled = enabledOptionIds.includes(o.id);
                        return (
                          <div key={o.id} className="flex items-center gap-3 text-sm">
                            <label className="flex shrink-0 items-center gap-1.5">
                              <input
                                type="checkbox"
                                checked={enabled}
                                onChange={(e) => setModeEnabled(mode, o.id, e.target.checked)}
                                className="rounded border-gray-300"
                              />
                              <span className="w-16 text-gray-700">{o.label}</span>
                            </label>
                            <span className="text-gray-500">Price (₱):</span>
                            <input
                              type="number"
                              min={0}
                              step="0.01"
                              disabled={!enabled}
                              value={
                                typeof modePrices[o.id] === "number"
                                  ? (modePrices[o.id]! / 100).toFixed(2)
                                  : ""
                              }
                              onChange={(e) => {
                                const next = { ...(sizePricesByMode ?? {}) };
                                const raw = e.target.value;
                                const pesos = raw === "" ? null : parseFloat(raw);
                                const currentMode = (next as any)[mode] ?? {};
                                if (pesos === null || Number.isNaN(pesos) || pesos < 0) {
                                  delete currentMode[o.id];
                                } else {
                                  currentMode[o.id] = Math.round(pesos * 100);
                                }
                                (next as any)[mode] = currentMode;
                                setSizePricesByMode(next);
                              }}
                              className="w-28 rounded border border-gray-300 px-2 py-1.5 text-sm disabled:bg-gray-100 disabled:text-gray-400"
                            />
                          </div>
                        );
                      })}
                    </div>
                    <div className="mt-3">
                      <label className="mb-1 block text-xs font-medium text-gray-600">Default size</label>
                      <select
                        value={defaultOptionId ?? ""}
                        onChange={(e) => setModeDefault(mode, e.target.value || null)}
                        disabled={enabledOptionIds.length === 0}
                        className="w-full rounded border border-gray-300 px-2 py-1.5 text-sm disabled:bg-gray-100 disabled:text-gray-500"
                      >
                        <option value="">{enabledOptionIds.length === 0 ? "No sizes enabled" : "Select default"}</option>
                        {enabledForDefault.map((o) => (
                          <option key={o.id} value={o.id}>
                            {o.label}
                          </option>
                        ))}
                      </select>
                      {hasEnabledNoDefault && (
                        <p className="mt-1 text-xs text-amber-600">Select a default size for this mode.</p>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
        <div>
          <label className="mb-2 block text-sm font-medium text-gray-700">Option Groups</label>
          <div className="flex flex-wrap gap-2">
            {(Array.isArray(optionGroups) ? optionGroups : []).map((g) => (
              <label key={g.id} className="flex items-center gap-2 rounded border px-3 py-2 text-sm">
                <input
                  type="checkbox"
                  checked={selectedGroupIds.includes(g.id)}
                  onChange={() => toggleOptionGroup(g.id)}
                  className="rounded border-gray-300"
                />
                {g.name}
              </label>
            ))}
            {(Array.isArray(optionGroups) ? optionGroups : []).length === 0 && (
              <span className="text-gray-500 text-sm">No option groups. Add them in Options.</span>
            )}
          </div>
        </div>
        <div className="flex items-center gap-2">
          <input
            type="checkbox"
            id="isActive"
            checked={isActive}
            onChange={(e) => setIsActive(e.target.checked)}
            className="rounded border-gray-300"
          />
          <label htmlFor="isActive" className="text-sm text-gray-700">Active</label>
        </div>
        {error && <p className="text-sm text-red-600">{error}</p>}
        <button
          type="submit"
          disabled={saving || !categoryId || !subCategoryId}
          className="rounded bg-blue-600 px-4 py-2 text-white hover:bg-blue-700 disabled:opacity-50"
        >
          {saving ? "Saving…" : "Save"}
        </button>
      </form>

      <section className="rounded border bg-white p-4">
        <h2 className="mb-3 text-lg font-medium">Recipe</h2>
        <table className="mb-4 min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-4 py-2 text-left text-xs font-medium uppercase text-gray-500">Ingredient</th>
              <th className="px-4 py-2 text-left text-xs font-medium uppercase text-gray-500">Qty</th>
              <th className="px-4 py-2 text-left text-xs font-medium uppercase text-gray-500">Unit</th>
              <th className="px-4 py-2 text-right text-xs font-medium uppercase text-gray-500">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {recipeLines.map((line, idx) => (
              <tr key={idx}>
                <td className="px-4 py-2 text-sm">{ingredientName(line.ingredientId)}</td>
                <td className="px-4 py-2 text-sm">{line.qtyPerItem}</td>
                <td className="px-4 py-2 text-sm">{line.unitCode}</td>
                <td className="px-4 py-2 text-right">
                  <button type="button" onClick={() => removeRecipeLine(idx)} className="text-red-600 hover:underline">
                    Remove
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <div className="flex flex-wrap items-end gap-2 border-t pt-3">
          <div>
            <label className="mb-1 block text-xs text-gray-500">Ingredient</label>
            <select
              value={newIngredientId}
              onChange={(e) => {
                setNewIngredientId(e.target.value);
                const ing = ingredients.find((i) => i.id === e.target.value);
                if (ing) setNewUnitCode(ing.unitCode);
              }}
              className="rounded border border-gray-300 px-2 py-1.5 text-sm"
            >
              <option value="">Select</option>
              {ingredients.map((ing) => (
                <option key={ing.id} value={ing.id}>{ing.name}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="mb-1 block text-xs text-gray-500">Qty</label>
            <input
              type="number"
              min={0}
              step="any"
              value={newQty}
              onChange={(e) => setNewQty(e.target.value)}
              placeholder="0"
              className="w-24 rounded border border-gray-300 px-2 py-1.5 text-sm"
            />
          </div>
          <div>
            <label className="mb-1 block text-xs text-gray-500">Unit</label>
            <input
              type="text"
              value={newUnitCode}
              onChange={(e) => setNewUnitCode(e.target.value)}
              placeholder="unit"
              className="w-20 rounded border border-gray-300 px-2 py-1.5 text-sm"
            />
          </div>
          <button type="button" onClick={addRecipeLine} className="rounded bg-gray-200 px-3 py-1.5 text-sm hover:bg-gray-300">
            Add
          </button>
        </div>

        {hasSizes && drinkSizes && drinkSizes.options.length > 0 && (
          <div className="mt-6 border-t pt-4">
            <h3 className="mb-2 text-sm font-medium text-gray-700">Per-size recipe (qty per drink)</h3>
            <p className="mb-3 text-xs text-gray-500">
              When sizes are enabled, you can specify how much of each ingredient is used for every size. Leave a cell
              blank or zero to indicate no additional consumption for that size.
            </p>
            <div className="space-y-4 overflow-x-auto">
              {recipeLines.length === 0 ? (
                <p className="text-xs text-gray-500">Add ingredients above to define per-size consumption.</p>
              ) : (
                DRINK_MODES.map((mode) => {
                  const enabledIds = drinkSizesByMode[mode].enabledOptionIds;
                  if (enabledIds.length === 0) return null;
                  const columns = drinkSizes.options.filter((o) => enabledIds.includes(o.id));
                  if (columns.length === 0) return null;
                  return (
                    <div key={mode} className="rounded border border-gray-200 bg-gray-50 p-3">
                      <h4 className="mb-2 text-sm font-medium text-gray-700">{MODE_LABELS[mode]}</h4>
                      <table className="min-w-full divide-y divide-gray-200 bg-white">
                        <thead className="bg-gray-50">
                          <tr>
                            <th className="px-3 py-2 text-left text-xs font-medium uppercase text-gray-500">Ingredient</th>
                            {columns.map((col) => (
                              <th
                                key={col.id}
                                className="px-3 py-2 text-center text-xs font-medium uppercase text-gray-500"
                              >
                                {MODE_LABELS[mode]} {col.label}
                              </th>
                            ))}
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-200">
                          {recipeLines.map((line) => (
                            <tr key={line.ingredientId}>
                              <td className="px-3 py-2 text-sm text-gray-700">
                                {ingredientName(line.ingredientId)}{" "}
                                <span className="text-xs text-gray-400">({line.unitCode})</span>
                              </td>
                              {columns.map((col) => {
                                const existing = sizeRecipeLines.find(
                                  (r) =>
                                    r.ingredientId === line.ingredientId &&
                                    r.baseType === mode &&
                                    r.sizeCode === col.label
                                );
                                const value = existing ? existing.qtyPerItem.toString() : "";
                                return (
                                  <td key={col.id} className="px-3 py-2 text-center text-sm">
                                    <input
                                      type="number"
                                      min={0}
                                      step="any"
                                      value={value}
                                      onChange={(e) => {
                                        const raw = e.target.value;
                                        setSizeRecipeLines((prev) => {
                                          const next = [...prev];
                                          const idx = next.findIndex(
                                            (r) =>
                                              r.ingredientId === line.ingredientId &&
                                              r.baseType === mode &&
                                              r.sizeCode === col.label
                                          );
                                          const parsed = raw === "" ? NaN : parseFloat(raw);
                                          if (!raw || Number.isNaN(parsed) || parsed < 0) {
                                            if (idx >= 0) next.splice(idx, 1);
                                            return next;
                                          }
                                          const qty = parsed;
                                          if (idx >= 0) {
                                            next[idx] = {
                                              ...next[idx],
                                              qtyPerItem: qty,
                                            };
                                          } else {
                                            next.push({
                                              ingredientId: line.ingredientId,
                                              baseType: mode,
                                              sizeCode: col.label,
                                              qtyPerItem: qty,
                                              unitCode: line.unitCode,
                                            });
                                          }
                                          return next;
                                        });
                                      }}
                                      className="w-20 rounded border border-gray-300 px-2 py-1 text-sm"
                                    />
                                  </td>
                                );
                              })}
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        )}

        <button
          type="button"
          onClick={saveRecipe}
          disabled={saving}
          className="mt-3 rounded bg-blue-600 px-4 py-2 text-sm text-white hover:bg-blue-700 disabled:opacity-50"
        >
          {saving ? "Saving recipe…" : "Save recipe"}
        </button>
      </section>
    </div>
  );
}
